package com.hospital.management.util;import org.junit.jupiter.api.Test;import java.time.*;import java.util.*;import static org.junit.jupiter.api.Assertions.*;
class TimeSlotGeneratorTest{@Test void normal(){assertEquals(List.of(LocalTime.of(9,0),LocalTime.of(9,30),LocalTime.of(10,0),LocalTime.of(10,30)),TimeSlotGenerator.generateSlots(LocalTime.of(9,0),LocalTime.of(11,0),30));}@Test void exactBoundary(){assertEquals(2,TimeSlotGenerator.generateSlots(LocalTime.NOON,LocalTime.of(13,0),30).size());}@Test void partialExcluded(){assertEquals(2,TimeSlotGenerator.generateSlots(LocalTime.of(9,0),LocalTime.of(10,10),30).size());}@Test void invalid(){assertThrows(IllegalArgumentException.class,()->TimeSlotGenerator.generateSlots(LocalTime.NOON,LocalTime.NOON,30));assertThrows(IllegalArgumentException.class,()->TimeSlotGenerator.generateSlots(LocalTime.NOON,LocalTime.of(13,0),0));}}
